node -e '
async function run() {
  const { chromium } = require("playwright");
  const browser = await chromium.launch();
  const page = await browser.newPage();
  await page.goto("http://127.0.0.1:8765/chart.html");

  const layout = await page.evaluate(() => {
    const groups = Array.from(document.querySelectorAll(".mark-group.role-scope"));
    return groups.map(g => {
      const rect = g.getBoundingClientRect();
      return {
        className: g.className.baseVal,
        x: rect.x,
        y: rect.y,
        width: rect.width,
        height: rect.height
      };
    });
  });
  console.log(JSON.stringify(layout, null, 2));
  await browser.close();
}
run();
'
